import TermSection from "./TermSection"
import { useContext, useEffect, useState } from "react"
import { StoreContext } from "src/contexts"
import { Button } from "antd"
import { useNavigate } from "react-router-dom"
import ROUTER from "src/router/ROUTER"
import STORAGE, { getStorage } from "src/lib/storage"
import notice from "src/components/Notice"
const contentSection = [
  {
    title: "Điều Kiện",
    content: (
      <>
        <p className="mt-20 fs-20">Tiêu chuẩn hội viên cá nhân</p>
        <ul className="custom-ul fs-15">
          <li>
            Công dân Việt Nam là bác sỹ, y sỹ, kỹ thuật viên trung, cao cấp;
          </li>
          <li>Giảng viên, chuyên gia trong và ngoài ngành y tế;</li>
          <li>
            Đoàn viên, người lao động thuộc và trực thuộc Công đoàn Y tế Việt
            Nam;
          </li>
          <li>
            Người lao động thuộc các tổ chức phối hợp với Công đoàn Y tế Việt
            Nam trong cả nước;
          </li>
          <li>
            Người hoạt động trong lĩnh vực tư vấn và hỗ trợ nâng cao sức khỏe
            toàn diện: thể chất, tinh thần, lối sống phòng chống bệnh lây nhiễm,
            không lây nhiễm, bệnh nghề nghiệp, bệnh mới nổi cho cán bộ y tế và
            cộng đồng.
          </li>
        </ul>

        <p className="fs-20 mt-20">Tiêu chuẩn hội viên Tổ Chức</p>
        <ul className="custom-ul fs-15">
          <li>
            Tổ chức Việt Nam được thành lập theo quy định của pháp luật, có tư
            cách pháp nhân, hoạt động trong lĩnh vực liên quan và hỗ trợ tư vấn
            nâng cao sức khỏe toàn diện: thể chất, tinh thần, lối sống phòng
            chống bệnh lây nhiễm, không lây nhiễm, bệnh nghề nghiệp, bệnh mới
            nổi cho cán bộ y tế và cộng đồng theo quy định của pháp luật.
          </li>
          <li>
            Đại diện cho hội viên tổ chức tham gia Hiệp hội phải là công dân
            Việt Nam.
          </li>
        </ul>
      </>
    ),
  },
  {
    title: "Thủ Tục Tham Gia Hội",
    content: (
      <div className="mt-40">
        <ul className="custom-ul">
          <li>
            <strong>Điều kiện và hồ sơ gia nhập:</strong> Có đủ điều kiện theo
            quy định tại Điều 8 Điều lệ này, có nguyện vọng gia nhập Hiệp hội
            gửi Đơn xin gia nhập theo mẫu
            <span className="red">
              {" "}
              do Hiệp hội quy định (thông qua Văn phòng Hiệp hội){" "}
            </span>{" "}
            kèm hồ sơ gồm:
            <ul>
              <li>
                <strong>Đối với công dân Việt Nam:</strong>
                <span className="red">
                  {" "}
                  Bản chứng thực CMND/CCCD hoặc hộ chiếu còn thời hạn và 01 ảnh
                  thẻ.{" "}
                </span>
              </li>
              <li>
                <strong>Đối với hội viên tổ chức:</strong>
                <span className="red">
                  {" "}
                  Lý lịch trích ngang và 01 ảnh thẻ của người đại diện.{" "}
                </span>
              </li>
            </ul>
          </li>
          <li>
            Văn phòng Hiệp hội tổng hợp, báo cáo Ban Thường vụ. Căn cứ quy chế
            làm việc, Ban Thường vụ ra quyết định kết nạp và thông báo đến Ban
            Chấp hành tại kỳ họp gần nhất.
          </li>
          <li>
            Trong vòng <span className="red">15 ngày làm việc</span> kể từ khi
            nhận Đơn, Ban Thường vụ xem xét, quyết định kết nạp hội viên.
            <span className="red">
              {" "}
              Hội viên đóng hội phí và được cấp thẻ hội viên (nếu có).{" "}
            </span>
          </li>
          <li>
            Việc công bố hội viên mới được tiến hành tại Hội nghị Ban Chấp hành,
            Ban Thường vụ hoặc thông báo bằng văn bản.
          </li>
        </ul>
      </div>
    ),
  },
  {
    title: "Thủ Tục Rút Khỏi Hội",
    content: (
      <div className="mt-40">
        <ul className="custom-ul">
          <li>
            <strong>Ra khỏi Hiệp hội:</strong> Hội viên tự nguyện gửi Đơn (qua
            Văn phòng Hội). Trong 15 ngày làm việc, sau khi hoàn tất bàn giao
            công việc (nếu có), Ban Thường vụ xem xét, ra quyết định chấm dứt tư
            cách hội viên và thông báo bằng văn bản.
          </li>
          <li>
            <strong>Khai trừ hội viên:</strong> Theo nghị quyết của Ban Thường
            vụ trong các trường hợp:
            <ul>
              <li>
                Vi phạm pháp luật hoặc Điều lệ Hiệp hội gây hậu quả nghiêm
                trọng.
              </li>
              <li>
                Bị truy cứu trách nhiệm hình sự hoặc bị tước quyền công dân.
              </li>
              <li>
                Không đóng hội phí dù đã được nhắc nhở 2 lần bằng văn bản hoặc
                email.
              </li>
            </ul>
          </li>
          <li>
            <strong>Trường hợp đương nhiên mất tư cách:</strong> Mất hoặc bị
            tuyên bố mất tích theo pháp luật.
          </li>
          <li>
            <strong>Bàn giao:</strong> Trước khi rút khỏi Hiệp hội, hội viên
            phải bàn giao công việc, tài sản, tài chính liên quan.
          </li>
          <li>
            <strong>Quyền khiếu nại:</strong> Hội viên bị chấm dứt tư cách có
            quyền khiếu nại lên Ban Chấp hành hoặc Đại hội.
            <span className="red"> Quyết định của Đại hội là cuối cùng. </span>
          </li>
        </ul>
      </div>
    ),
  },
]

const TermsConditionsContent = () => {
  const { loginStore } = useContext(StoreContext)
  const { isLoginContext } = loginStore
  const navigate = useNavigate()
  const [isLoggedIn, setIsLoggedIn] = useState(false)

  // Check if user is logged in
  useEffect(() => {
    const token = getStorage(STORAGE.TOKEN)
    setIsLoggedIn(!!token)
  }, [isLoginContext])

  const renderTopButtons = () => {
    const handleRegisterClick = path => {
      const token = getStorage(STORAGE.TOKEN)
      if (!token) {
        notice({
          msg: "Vui lòng đăng nhập để tiếp tục đăng ký hội viên",
          isSuccess: false,
        })
        return
      }
      navigate(path)
    }

    return (
      <div
        className="btn-group"
        style={{
          justifyContent: "flex-end",
          marginBottom: "20px",
          marginRight: "50px",
        }}
      >
        {
          !isLoggedIn && (
            <>
              <Button
                type="primary"
                className="mr-10"
                onClick={() => handleRegisterClick(ROUTER.DANG_KI_CA_NHAN)}
              >
                Đăng kí cá nhân
              </Button>
              <Button
                type="primary"
                onClick={() => handleRegisterClick(ROUTER.DANG_KI_DOANH_NGHIEP)}
              >
                Đăng kí hội viên doanh nghiệp
              </Button>
            </>
          )
          // <>
          /* <Button
              type="primary"
              className="mr-10"
              onClick={() => navigate(ROUTER.KHIEU_NAI)}
            >
              Khiếu nại
            </Button>
            <Button
              type="primary"
              className="mr-10"
              onClick={() => navigate(ROUTER.HOI_PHI)}
            >
              Hội phí
            </Button>
            <Button
              type="primary"
              onClick={() => navigate(ROUTER.RUT_KHOI_HOI)}
            >
              Rút khỏi hội
            </Button>
          </> */
        }
      </div>
    )
  }

  return (
    <div className="d-flex-column">
      {renderTopButtons()}
      {contentSection.map((section, index) => (
        <TermSection
          key={index}
          title={section.title}
          content={section.content}
          showLine={index < contentSection.length - 1}
        />
      ))}
    </div>
  )
}

export default TermsConditionsContent
